import React, { useState } from 'react';

/* ── Default task list ───────────────────────────────────────── */
const DEFAULT_TASKS = [
    { id: 1, title: 'Record a 2-minute self-introduction', xp: 50, category: 'Practice', icon: '🎤' },
    { id: 2, title: 'Complete 1 HR interview question', xp: 75, category: 'Interview', icon: '💼' },
    { id: 3, title: 'Join a Group Discussion room', xp: 60, category: 'GD', icon: '👥' },
    { id: 4, title: 'Read today\'s communication tip', xp: 20, category: 'Learning', icon: '📖' },
    { id: 5, title: 'Achieve score ≥ 70 in any session', xp: 100, category: 'Challenge', icon: '⚡' },
];

const categoryColors = {
    Practice: 'bg-primary-500/20 text-primary-400 border-primary-500/30',
    Interview: 'bg-neon-yellow/20 text-neon-yellow border-neon-yellow/30',
    GD: 'bg-neon-green/20 text-neon-green border-neon-green/30',
    Learning: 'bg-accent-500/20 text-accent-400 border-accent-500/30',
    Challenge: 'bg-neon-pink/20 text-neon-pink border-neon-pink/30',
};

/**
 * DailyTaskCard
 * Props:
 *   tasks           – array of { id, title, xp, category, icon, completed }
 *   onComplete(id)  – called when a task is marked complete
 *   loading         – show skeleton
 */
export default function DailyTaskCard({ tasks, onComplete, loading = false }) {
    const [localDone, setLocalDone] = useState({});

    const taskList = tasks?.length ? tasks : DEFAULT_TASKS;

    const handleToggle = (id) => {
        if (localDone[id]) return; // already done, no undo
        setLocalDone(prev => ({ ...prev, [id]: true }));
        onComplete?.(id);
    };

    const doneCount = taskList.filter(t => t.completed || localDone[t.id]).length;
    const totalXP = taskList.reduce((acc, t) =>
        (t.completed || localDone[t.id]) ? acc + (t.xp || 0) : acc, 0
    );

    if (loading) {
        return (
            <div className="glass-card p-5 space-y-3 animate-pulse">
                <div className="h-4 w-32 bg-white/5 rounded" />
                {[1, 2, 3].map(i => <div key={i} className="h-14 bg-white/5 rounded-xl" />)}
            </div>
        );
    }

    return (
        <div className="glass-card p-5">
            {/* Header */}
            <div className="flex items-center justify-between mb-4">
                <div>
                    <h3 className="section-title text-base">Daily Tasks</h3>
                    <p className="section-subtitle text-xs">
                        {doneCount}/{taskList.length} completed · +{totalXP} XP earned
                    </p>
                </div>
                <div className="flex flex-col items-end gap-1">
                    <span className="text-white font-bold text-lg leading-none">{doneCount}</span>
                    <span className="text-white/30 text-[10px]">done</span>
                </div>
            </div>

            {/* Overall progress */}
            <div className="progress-bar mb-4">
                <div
                    className="progress-fill transition-all duration-700"
                    style={{ width: taskList.length ? `${(doneCount / taskList.length) * 100}%` : '0%' }}
                />
            </div>

            {/* Task list */}
            <ul className="space-y-2">
                {taskList.map(task => {
                    const done = task.completed || localDone[task.id];
                    return (
                        <li key={task.id}>
                            <button
                                onClick={() => handleToggle(task.id)}
                                disabled={done}
                                className={`
                  w-full flex items-center gap-3 px-3 py-3 rounded-xl text-left
                  transition-all duration-200 group
                  ${done
                                        ? 'bg-neon-green/5 border border-neon-green/20 cursor-default'
                                        : 'hover:bg-white/5 border border-white/5 hover:border-white/10'
                                    }
                `}
                            >
                                {/* Checkbox */}
                                <div className={`task-checkbox ${done ? 'checked' : ''}`}>
                                    {done && (
                                        <svg className="w-3 h-3 text-dark-900" fill="none" viewBox="0 0 24 24"
                                            stroke="currentColor" strokeWidth={3}>
                                            <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                                        </svg>
                                    )}
                                </div>

                                {/* Icon + text */}
                                <span className="text-lg flex-shrink-0">{task.icon}</span>
                                <p className={`flex-1 text-sm leading-snug ${done ? 'text-white/30 line-through' : 'text-white/80'}`}>
                                    {task.title}
                                </p>

                                {/* Category + XP */}
                                <div className="flex flex-col items-end gap-1 flex-shrink-0">
                                    <span className={`badge border text-[9px] ${categoryColors[task.category] || 'bg-white/5 text-white/40 border-white/10'}`}>
                                        {task.category}
                                    </span>
                                    <span className={`text-[10px] font-semibold ${done ? 'text-neon-green' : 'text-neon-yellow'}`}>
                                        {done ? '✓' : '+'}{task.xp} XP
                                    </span>
                                </div>
                            </button>
                        </li>
                    );
                })}
            </ul>

            {/* All done message */}
            {doneCount === taskList.length && (
                <div className="mt-4 p-3 rounded-xl bg-neon-green/10 border border-neon-green/20 text-center">
                    <p className="text-neon-green font-semibold text-sm">🎉 All tasks complete! Amazing work!</p>
                </div>
            )}
        </div>
    );
}
